.mq-band  { overflow: hidden; }
.mq-track {
  display: flex; width: max-content;
  animation: mq-scroll 24s linear infinite;
}
.mq-group { display: flex; align-items: center; flex: 0 0 auto; }
/* 핵심: 동일 콘텐츠 2벌 → -50% 지점 = 시작과 완전히 같은 그림 */
@keyframes mq-scroll { to { transform: translateX(-50%); } }

// 복제는 JS 한 줄 — HTML은 원본 1벌만 유지 (수정 누락 방지)
var track = document.querySelector(".mq-track");
var clone = track.querySelector(".mq-group").cloneNode(true);
clone.setAttribute("aria-hidden", "true"); // 스크린리더 중복 낭독 방지
track.appendChild(clone);

.lw-band {
  overflow: hidden;
  /* 양끝 80px 페이드 — 로고가 잘려 보이지 않게 */
  -webkit-mask-image: linear-gradient(90deg,
    transparent, #000 80px, #000 calc(100% - 80px), transparent);
  mask-image: linear-gradient(90deg,
    transparent, #000 80px, #000 calc(100% - 80px), transparent);
}
.lw-logo { filter: grayscale(1); opacity: 0.45;
           transition: filter 180ms, opacity 180ms; }
.lw-band:hover .lw-track { animation-play-state: paused; }
.lw-band:hover .lw-logo  { filter: none; opacity: 1; }

// 로고 이미지라면 <img>를 그대로 복제해도 동일하게 동작
var track = document.querySelector(".lw-track");
var clone = track.querySelector(".lw-group").cloneNode(true);
clone.setAttribute("aria-hidden", "true");
track.appendChild(clone);

.dd-track {
  display: flex; width: max-content;
  animation: dd-scroll 26s linear infinite;
}
/* 2행은 키프레임 재사용 + direction·duration만 변경 */
.dd-row2 .dd-track {
  animation-direction: reverse;
  animation-duration: 30s;
}
@keyframes dd-scroll { to { transform: translateX(-50%); } }

// 트랙이 몇 개든 같은 복제 루틴으로 처리
Array.prototype.forEach.call(
  document.querySelectorAll(".dd-track"),
  function(track) {
    var clone = track.querySelector(".dd-group").cloneNode(true);
    clone.setAttribute("aria-hidden", "true");
    track.appendChild(clone);
  }
);

/* CSS 애니메이션 없음 — transform은 JS 틱이 직접 구동 */
.hp-band  { overflow: hidden; }
.hp-track { display: flex; width: max-content;
            will-change: transform; }

var FAST = 160, SLOW = 24;            // px/s
var speed = FAST, target = FAST, offset = 0;
band.addEventListener("mouseenter", function() { target = SLOW; });
band.addEventListener("mouseleave", function() { target = FAST; });
function tick() {
  var dt = Math.min(64, Date.now() - last); last += dt;
  speed += (target - speed) * Math.min(1, dt * 0.005); // 지수 보간
  offset = (offset + speed * dt / 1000) % group.offsetWidth;
  track.style.transform = "translateX(" + (-offset) + "px)";
  setTimeout(tick, 16);
}

.sv-band  { overflow: hidden; }
.sv-track { display: flex; width: max-content;
            will-change: transform; }
/* transform은 JS가 translateX + skewX를 함께 갱신 */

var BASE = 90, vel = 0, offset = 0, lastY = window.pageYOffset;
function tick() {
  var y = window.pageYOffset;
  vel += (y - lastY) * 5;              // 스크롤 델타 가산
  lastY = y;
  vel *= Math.max(0, 1 - dt * 0.004);  // 감쇠 — 멈추면 기본 속도로
  offset = (offset + (BASE + Math.abs(vel)) * dt / 1000) % half;
  var skew = Math.max(-10, Math.min(10, vel * 0.015));
  track.style.transform =
    "translateX(" + (-offset) + "px) skewX(" + skew + "deg)";
  setTimeout(tick, 16);
}

.vt-window { height: 24px; overflow: hidden; } /* 1줄 창 */
.vt-list li { height: 24px; line-height: 24px; }  /* 줄 높이 = 이동 단위 */
.vt-list { animation: vt-roll 10s infinite; }      /* 기본 ease — 스텝마다 감속 */
@keyframes vt-roll {
  0%, 21%  { transform: translateY(0); }      /* hold 2.1s */
  25%, 46% { transform: translateY(-24px); }  /* 전환 0.4s + hold */
  50%, 71% { transform: translateY(-48px); }
  75%, 96% { transform: translateY(-72px); }
  100%     { transform: translateY(-96px); }  /* = 첫 항목 클론 위치 */
}

var list = document.querySelector(".vt-list");
var first = list.children[0].cloneNode(true);
first.setAttribute("aria-hidden", "true");
list.appendChild(first); // 마지막 칸 = 첫 항목 → 루프 리셋이 안 보임

.ist-track { display: flex; width: max-content;
             animation: ist-scroll 32s linear infinite; }
.ist-card  {
  width: clamp(180px, 22vw, 240px);
  border-radius: 16px; flex: 0 0 auto;
  transition: transform 180ms ease;
}
.ist-card:hover { transform: scale(1.07); } /* 카드만 개별 확대 */
@keyframes ist-scroll { to { transform: translateX(-50%); } }

var track = document.querySelector(".ist-track");
var clone = track.querySelector(".ist-group").cloneNode(true);
clone.setAttribute("aria-hidden", "true");
track.appendChild(clone);

.of-fill { color: #fff; }
.of-line { color: transparent;
           -webkit-text-stroke: 2px rgba(255,255,255,0.65); }
/* 기울인 행 — 110vw 오버사이즈로 회전 모서리 공백 제거 */
.of-band { overflow: hidden; width: 110vw; margin-left: -5vw; }
.of-row2 { transform: rotate(-2deg); }
.of-row2 .of-track { animation-direction: reverse;
                     animation-duration: 34s; }

Array.prototype.forEach.call(
  document.querySelectorAll(".of-track"),
  function(track) {
    var clone = track.querySelector(".of-group").cloneNode(true);
    clone.setAttribute("aria-hidden", "true");
    track.appendChild(clone);
  }
);

.dg-band {
  overflow: hidden;
  cursor: grab; user-select: none;
  touch-action: pan-y; /* 세로 스크롤은 살리고 가로만 점유 */
}
.dg-band.is-drag { cursor: grabbing; }

// 드래그 중: 포인터 1:1 직결 + 릴리즈 속도 기록
offset -= dx;
vel = Math.max(-2400, Math.min(2400, -dx / mdt * 1000));
// 릴리즈 후: 관성 감쇠와 기본 흐름 복귀를 한 식으로
if (!dragging) {
  offset += vel * dt / 1000;
  vel += (BASE - vel) * Math.min(1, dt * 0.002);
}
// 모듈러 래핑 — 어느 방향으로 던져도 무한
offset = ((offset % half) + half) % half;
track.style.transform = "translateX(" + (-offset) + "px)";

.tk-bar      { display: flex; }            /* 라벨 + 뷰포트 */
.tk-breaking { flex: 0 0 auto; background: #e11d48; }
.tk-view     { flex: 1; overflow: hidden; } /* 흐름은 여기만 */
.tk-track    { display: flex; width: max-content;
               animation: tk-scroll 20s linear infinite; }
.tk-view:hover .tk-track { animation-play-state: paused; }
.tk-item:hover { text-decoration: underline;
                 text-underline-offset: 4px; }
@keyframes tk-scroll { to { transform: translateX(-50%); } }

